import { User } from 'discord.js';
import UserData from './UserData';

declare interface LeaderboardData {
    userID: string,
    level: number,
    totalXP: number,
    xp: number,
    maxXP: number,
    difference: number,
    user: User,

    /**
    * The user data that is stored in database.
    * Use it in case if the requested user
    * is not on your server.
    */
    userData: UserData
}